import { describe, expect, it } from 'vitest';

import {
  LIGHT_FIELD_HEIGHT,
  LIGHT_FIELD_WIDTH,
  LIGHT_MODEL_BUNDLE_SCHEMA,
  createLightModelBundle,
  lightBytesToBase64,
  parseLightModelBundle,
  parseLightMonsterMeshArtifact,
  reconstructLightModelBundle,
  type LightTranslationArtifactInput,
  type LightTranslationSettings,
} from '../src/light-model-artifact';

const SETTINGS: LightTranslationSettings = {
  fovea: { x: 0.55, y: 0.45 },
  exposure: 0.1,
  modeCount: 8,
  pupilMm: 4.1,
  focus: 0.04,
  glare: 0.25,
};

function sampleTranslation(): LightTranslationArtifactInput {
  const texture = new Uint8Array(LIGHT_FIELD_WIDTH * LIGHT_FIELD_HEIGHT * 4);
  for (let idx = 0; idx < LIGHT_FIELD_WIDTH * LIGHT_FIELD_HEIGHT; idx += 1) {
    const off = idx * 4;
    texture[off] = idx % 255;
    texture[off + 1] = (idx * 3) % 255;
    texture[off + 2] = 140;
    texture[off + 3] = 210;
  }
  return {
    width: LIGHT_FIELD_WIDTH,
    height: LIGHT_FIELD_HEIGHT,
    texture,
    modes: [
      {
        m: 1,
        n: 3,
        amplitude: 1,
        signedAmplitude: 1,
        omega: 0.32,
        phase: 0,
        color: [0.8, 0.55, 0.9],
        energy: 0.68,
      },
      {
        m: 2,
        n: 1,
        amplitude: 0.64,
        signedAmplitude: -0.64,
        omega: 0.41,
        phase: Math.PI,
        color: [0.4, 0.8, 0.7],
        energy: 0.18,
      },
    ],
    metrics: {
      meanLuminance: 0.42,
      opticalSpread: 1.12,
      rodLoad: 0.03,
      coneBalance: 0.5,
      fovealLoad: 0.2,
      opponentEnergy: 0.08,
      corticalEnergy: 0.31,
      dominantFrequency: 0.32,
      retainedEnergy: 0.86,
    },
  };
}

describe('light model artifact', () => {
  it('round-trips bundle JSON into a Monster Mesh projection', () => {
    const bundle = createLightModelBundle(sampleTranslation(), SETTINGS, 'scene.png');
    const artifact = parseLightMonsterMeshArtifact(JSON.stringify(bundle));

    expect(artifact.kind).toBe('light-model-bundle');
    expect(artifact.schema).toBe(LIGHT_MODEL_BUNDLE_SCHEMA);
    expect(artifact.sourceName).toBe('scene.png');
    expect(artifact.width).toBe(LIGHT_FIELD_WIDTH);
    expect(artifact.height).toBe(LIGHT_FIELD_HEIGHT);
    expect(artifact.modeCount).toBe(2);
    expect(artifact.dominantModes).toHaveLength(2);
    expect(artifact.metrics.retainedEnergy).toBe(0.86);
    expect(artifact.metrics.modeLoss).toBeCloseTo(0.14);
    expect(artifact.previews.sourceEstimateRgba).toHaveLength(
      LIGHT_FIELD_WIDTH * LIGHT_FIELD_HEIGHT * 4,
    );
    expect(artifact.previews.retinalRgba).toHaveLength(
      LIGHT_FIELD_WIDTH * LIGHT_FIELD_HEIGHT * 4,
    );
    expect(artifact.previews.corticalRgba).toHaveLength(
      LIGHT_FIELD_WIDTH * LIGHT_FIELD_HEIGHT * 4,
    );
  });

  it('rejects unsupported schemas', () => {
    const bundle = createLightModelBundle(sampleTranslation(), SETTINGS, 'scene.png');
    const invalid = { ...bundle, schema: 'ai.forkjoin.other' };

    expect(() => parseLightModelBundle(JSON.stringify(invalid))).toThrow(
      /unsupported model bundle schema/i,
    );
  });

  it('rejects corrupt texture payloads', () => {
    const bundle = createLightModelBundle(sampleTranslation(), SETTINGS, 'scene.png');
    const invalid = {
      ...bundle,
      model: {
        ...bundle.model,
        textureRgbaBase64: lightBytesToBase64(new Uint8Array([1, 2, 3])),
      },
    };

    expect(() => reconstructLightModelBundle(parseLightModelBundle(JSON.stringify(invalid)))).toThrow(
      /wrong length/i,
    );
  });
});
